@app.route('/reset-mfa/<token>', methods=['POST'])
def reset_mfa_token(token):
    email = ts.loads(token, salt=app.config['PASSWORD_SALT'], max_age=86400)  # Max age is in seconds; here it's one day
    
    if not email or users[email]['email'] != email:
        return jsonify({'message': 'Invalid token.'}), 400
    
    users[email]['mfa'] = False
    return jsonify({'message': f"Multi-factor authentication has been disabled for {email}."})

